// Generated. Subsetted (Latin) open-source fonts bundled so each vibe's
// typography renders identically in browsers and headless rasterizers, with no
// network or locally-installed fonts required. See assets/fonts/ATTRIBUTION.md
// for sources and licences (SIL OFL 1.1 / Apache-2.0). Base64 is the raw TTF.
/* eslint-disable */

/** Family name → base64-encoded subsetted TTF. */
export const FONT_TTF_BASE64: Record<string, string> = {
  "Comic Neue": '',
  "Cousine": '',
  "Gloria Hallelujah": '',
  "Caveat": '',
  "Permanent Marker": '',
  "Spectral": '',
  "Schoolbell": '',
  "EB Garamond": '',
  "Orbitron": '',
  "Bangers": '',
  "VT323": '',
  "Quicksand": '',
  "Playfair Display": '',
  "Special Elite": '',
  "IBM Plex Sans": '',
  "Cinzel": '',
};

/** Pull the first family name out of a CSS font-family stack, unquoted. */
export function primaryFamily(fontFamily: string): string {
  const first = fontFamily.split(',')[0]?.trim() ?? '';
  return first.replace(/^['"]|['"]$/g, '');
}

/** The bundled font for a font-family stack, or undefined if none is bundled. */
export function bundledFontFor(fontFamily: string): { family: string; ttfBase64: string } | undefined {
  const family = primaryFamily(fontFamily);
  const ttfBase64 = FONT_TTF_BASE64[family];
  return ttfBase64 ? { family, ttfBase64 } : undefined;
}
